form.script:
(function() {
    var checkoutToken = "";
    var reference = "";

    // Écoute les événements du modal HelcimPay.js
    window.addEventListener('message', function(event) {
        var helcimPayJsIdentifierKey = 'helcim-pay-js-' + checkoutToken;

        if (event.data.eventName === helcimPayJsIdentifierKey) {

            if (event.data.eventStatus === 'ABORTED') {
                // Paiement annulé par le client
                console.log('Helcim: Paiement annulé.');
                window.location.href = '/payment/status';
            }

            if (event.data.eventStatus === 'SUCCESS') {
                // Paiement réussi : validation côté serveur
                var transactionData = event.data.eventMessage.data || event.data.eventMessage;

                // Appel AJAX vers le contrôleur Odoo pour valider la transaction
                fetch('/payment/helcim/validate', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        jsonrpc: '2.0',
                        method: 'call',
                        params: {
                            reference: reference,
                            transaction_data: transactionData,
                        }
                    })
                })
                .then(function(response) { return response.json(); })
                .then(function(result) {
                    console.log('Helcim: Résultat de validation:', result);
                    window.location.href = '/payment/status';
                })
                .catch(function(error) {
                    console.error('Helcim: Erreur de validation:', error);
                    window.location.href = '/payment/status';
                });
            }

            if (event.data.eventStatus === 'HIDE') {
                // Modal fermé
                console.log('Helcim: Modal fermé.');
            }
        }
    });

    // Affichage du modal HelcimPay.js avec le checkoutToken
    if (typeof appendHelcimIframe === 'function') {
        appendHelcimIframe(checkoutToken);
    } else {
        document.addEventListener('DOMContentLoaded', function() {
            if (typeof appendHelcimIframe === 'function') {
                appendHelcimIframe(checkoutToken);
            }
        });
    }
})();
